import 'package:flutter/material.dart';import 'package:flutter/services.dart';import 'package:randevu_sistem/yeni/urun_ekle.dart';import 'package:barcode_scan2/barcode_scan2.dart';class UrunList extends StatefulWidget {  const UrunList({Key? key}) : super(key: key);  @override  _UrunListState createState() =>      _UrunListState();}class _UrunListState extends State<UrunList> {  String _scanBarcode = 'Bilinmiyor';  @override  void initState() {    super.initState();  }  Future<void> scanQR() async {    String barcodeScanRes;    // Platform mesajları başarısız olabilir, bu yüzden try/catch kullanıyoruz.    try {      var result = await BarcodeScanner.scan(); // Barkod tarama başlatılır      barcodeScanRes = result.rawContent; // Tarama sonucunu al      print(barcodeScanRes);    } on PlatformException {      barcodeScanRes = 'Platform sürümü alınamadı.';    }    // Widget ağacından kaldırılmışsa, yanıtı yok saymak istiyoruz.    if (!mounted) return;    setState(() {      _scanBarcode = barcodeScanRes;    });  }  Future<void> scanBarcodeNormal() async {    String barcodeScanRes;    // Platform mesajları başarısız olabilir, bu yüzden try/catch kullanıyoruz.    try {      var result = await BarcodeScanner.scan(); // Barkod tarama başlatılır      barcodeScanRes = result.rawContent; // Tarama sonucunu al      print(barcodeScanRes);    } on PlatformException {      barcodeScanRes = 'Platform sürümü alınamadı.';    }    // Widget ağacından kaldırılmışsa, yanıtı yok saymak istiyoruz.    if (!mounted) return;    setState(() {      _scanBarcode = barcodeScanRes;    });  }  @override  Widget build(BuildContext context) {    return Scaffold(      appBar: AppBar(          title: Text("Ürün Seçimi",style: TextStyle(color: Colors.black,fontSize: 20),),          toolbarHeight: 60,          backgroundColor: Colors.white,          actions: [            IconButton(                icon: Icon(                    Icons.add,                    color: Colors.black,                    size: 25.0),                onPressed: (){                  /*Navigator.push(                  context,                  MaterialPageRoute(                      builder: (context) => YeniUrun()),                );*/}            ),          ],          leading: IconButton(            icon: Icon(Icons.arrow_back, color: Colors.black),            onPressed: () => Navigator.of(context).pop(),          )      ),      body: _buildListView(),    );  }ListView _buildListView() {    return ListView(      children: <Widget>[        ListTile(          title: Text('Saç Boyası'),          trailing: Icon(Icons.keyboard_arrow_right),          onTap: () {            setState(() {            });            Future.delayed(const Duration(milliseconds: 200), () {              // When task is over, close the dialog              Navigator.pop(context);            });          },        ),        ListTile(          title: Text('Şampuan'),          trailing: Icon(Icons.keyboard_arrow_right),          onTap: () {            setState(() {            });            Future.delayed(const Duration(milliseconds: 200), () {              // When task is over, close the dialog              Navigator.pop(context);            });          },        ),        ElevatedButton(          onPressed: () => scanBarcodeNormal(),          child: Text('Barkod Tara'),style: ElevatedButton.styleFrom(          textStyle:          TextStyle(fontSize: 16, fontWeight: FontWeight.bold),          backgroundColor: Colors.purple[800], // background (button) color          foregroundColor: Colors.white,),),        const Divider(          height: 10.0,          thickness: 1,        ),        Text('Barkod : $_scanBarcode\n',          style: TextStyle(fontSize: 18,),          textAlign: TextAlign.center,)      ],    );  }}